function navavishkar_stay_facilities_table_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('navavishkar_stay_facilities_table');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'item_purchased_date' => Request::dateComponents('item_purchased_date', '1'),
		'type_of_item' => Request::val('type_of_item', ''),
		'SubCategory' => Request::val('SubCategory', ''),
		'Item_serial_no' => Request::val('Item_serial_no', ''),
		'particulars_of_supplier_name_address' => Request::val('particulars_of_supplier_name_address', ''),
		'ItemDescription' => Request::val('ItemDescription', ''),
		'BillNo' => Request::val('BillNo', ''),
		'BillDate' => Request::dateComponents('BillDate', ''),
		'QUANTITY' => Request::val('QUANTITY', ''),
		'CostoftheAssetinINR' => Request::val('CostoftheAssetinINR', ''),
		'TotalInvoiceValueinINR' => Request::val('TotalInvoiceValueinINR', ''),
		'CustodyDepartment' => Request::val('CustodyDepartment', ''),
		'custodian' => Request::lookup('custodian', ''),
		'remarks' => br2nl(Request::val('remarks', '')),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('navavishkar_stay_facilities_table', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		navavishkar_stay_facilities_table_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

