		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
	];

	// get existing values
	$old_data = getRecord('navavishkar_stay_facilities_table', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: navavishkar_stay_facilities_table_before_update
	if(function_exists('navavishkar_stay_facilities_table_before_update')) {
		$args = ['old_data' => $old_data];
		if(!navavishkar_stay_facilities_table_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'navavishkar_stay_facilities_table',
		backtick_keys_once($set),
		['`id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="navavishkar_stay_facilities_table_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('navavishkar_stay_facilities_table', $data['selectedID'], calculated_fields()['navavishkar_stay_facilities_table']);

	// hook: navavishkar_stay_facilities_table_after_update
	if(function_exists('navavishkar_stay_facilities_table_after_update')) {
		if($row = getRecord('navavishkar_stay_facilities_table', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!navavishkar_stay_facilities_table_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('navavishkar_stay_facilities_table', $selected_id);
}

